import re


def parse_duration(text):
    match = re.match(r"^(\d+)([hms])$", text)
    if not match:
        raise ValueError(f"invalid duration: {text}")
    value = int(match.group(1))
    unit = match.group(2)
    if unit == "h":
        return value * 3600
    if unit == "m":
        return value * 60
    return value
